  let vB = textureLoad(velRead, clamp(i - vec3(0, 1, 0), vec3(0), vec3(i32(res)-1)), 0).y;
  let vT = textureLoad(velRead, clamp(i + vec3(0, 1, 0), vec3(0), vec3(i32(res)-1)), 0).y;
